from abc import ABC, abstractmethod
import math

class Shape(ABC):
    @abstractmethod
    def area(self):
        pass

class Circle(Shape):
    def __init__(self, radius):
        self.radius = radius

    def area(self):
        return math.pi * self.radius ** 2

class Rectangle(Shape):
    def __init__(self, length, breadth):
        self.length = length
        self.breadth = breadth

    def area(self):
        return self.length * self.breadth

# Polymorphism in action
shapes = [Circle(5), Rectangle(4, 6), Circle(3)]
total_area = sum(s.area() for s in shapes)
print(f"Total Area: {total_area:.2f}")
# Output: Total Area: 130.54 (78.54 + 24 + 28.27)

class Complex:
    def __init__(self, real, imag):
        self.real = real
        self.imag = imag

    def __add__(self, other):
        # Overloads + operator
        return Complex(self.real + other.real, self.imag + other.imag)

    def __sub__(self, other):
        # Overloads - operator
        return Complex(self.real - other.real, self.imag - other.imag)

    def __str__(self):
        return f"{self.real} + {self.imag}i"

    def __repr__(self):
        return f"Complex({self.real}, {self.imag})"

c1 = Complex(3, 4)
c2 = Complex(1, 2)
c3 = c1 + c2    # Uses __add__
c4 = c1 - c2    # Uses __sub__
print(c3)  # Output: 4 + 6i
print(c4)  # Output: 2 + 2i

class Circle:
    def draw(self):
        print("Drawing a Circle 🟢")

class Square:
    def draw(self):
        print("Drawing a Square 🟦")

class Triangle:
    def draw(self):
        print("Drawing a Triangle 🔺")

# Polymorphic function - duck typing
def draw_shape(shape):
    shape.draw()  # Doesn't check type, just calls draw()

# Works with ANY object that has draw() method
shapes = [Circle(), Square(), Triangle()]
for s in shapes:
    draw_shape(s)

# Output:
# Drawing a Circle 🟢
# Drawing a Square 🟦
# Drawing a Triangle 🔺

class Calculator:
    def add(self, a, b=0, c=0):
        # Simulates method overloading
        return a + b + c

calc = Calculator()
print(calc.add(5))           # Output: 5 (single arg)
print(calc.add(5, 3))        # Output: 8 (two args)
print(calc.add(5, 3, 2))    # Output: 10 (three args)

# Using *args for variable arguments
class Calculator2:
    def add(self, *args):
        return sum(args)

calc2 = Calculator2()
print(calc2.add(1, 2))           # Output: 3
print(calc2.add(1, 2, 3, 4))    # Output: 10
print(calc2.add())               # Output: 0
